package com.example.loggingapi.api;

import com.example.loggingapi.service.HealthService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.Instant;
import java.util.LinkedHashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class HealthController {

    private static final Logger log = LoggerFactory.getLogger(HealthController.class);

    private final HealthService healthService;

    public HealthController(HealthService healthService) {
        this.healthService = healthService;
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, Object>> health() {
        log.debug("Received request: GET /api/health");
        Map<String, Object> body = healthService.health();
        log.info("Health check successful");
        return ResponseEntity.ok(body);
    }

    @GetMapping("/echo")
    public ResponseEntity<Map<String, Object>> echo(@RequestParam(defaultValue = "hello") String message) {
        log.debug("Received request: GET /api/echo message={}", message);
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("message", message);
        body.put("timestamp", Instant.now().toString());
        log.info("Echo successful");
        return ResponseEntity.ok(body);
    }
}

package com.example.loggingapi.service;

import org.slf4j.Logger;
